solution_code:
#include <iostream>

template <typename T>
T absVal(T x)
{
    return (x < 0) ? -x : x;
}

int main()
{
    double value;
    std::cin >> value;
    double result = absVal(value);
    std::cout << "abs: " << result << '\n';
    std::cout << "double: " << result * 2 << '\n';
    return 0;
}

