solution_code:
#include <iostream>

template <typename T>
T clampVal(T value, T lo, T hi)
{
    if (value < lo) return lo;
    if (value > hi) return hi;
    return value;
}

int main()
{
    double value, lo, hi;
    std::cin >> value >> lo >> hi;
    std::cout << clampVal(value, lo, hi) << '\n';
    return 0;
}
